// Suppliers + sourcing countries to monitor. Edit freely (commodity → countries).
return [
  { json: { supplier: 'Brazil beef suppliers', commodity: 'beef', country: 'Brazil', q: 'Brazil beef export OR cattle OR port' } },
  { json: { supplier: 'India buffalo meat', commodity: 'beef', country: 'India', q: 'India buffalo meat export ban OR price' } },
  { json: { supplier: 'Brazil/Ukraine chicken', commodity: 'chicken', country: 'Brazil', q: 'Brazil chicken poultry export avian flu' } },
  { json: { supplier: 'Egypt potatoes', commodity: 'potato', country: 'Egypt', q: 'Egypt potato export price weather' } },
  { json: { supplier: 'KSA logistics', commodity: 'all', country: 'Saudi Arabia', q: 'Saudi Arabia port Jeddah Dammam shipping delay customs' } }
];

// Parse RSS <item> into {title, source, url, date}. Keep most-recent 8 per target.
const xml = $input.first().json.data || $input.first().json.body || '';
const t = String(xml);
const items = [];
const re = /<item>([\s\S]*?)<\/item>/g; let m;
const pick = (s, tag) => { const r = new RegExp('<'+tag+'>([\\s\\S]*?)<\\/'+tag+'>').exec(s); return r ? r[1].replace(/<!\[CDATA\[|\]\]>/g,'').trim() : ''; };
while ((m = re.exec(t)) && items.length < 8) {
  const b = m[1];
  items.push({ title: pick(b,'title'), url: pick(b,'link'), source: pick(b,'source') || 'Google News', date: pick(b,'pubDate') });
}
const meta = $('Suppliers + countries').item.json;
return [{ json: { ...meta, articles: items } }];

