// Parse model JSON, then DROP any risk without a real citation (accuracy guard).
let out;
try { out = JSON.parse($json.choices[0].message.content); } catch (e) { return []; }
out.risks = (out.risks || []).filter(r => r && r.citation && r.citation.url && r.citation.source);
out.generated_at = $now.toISO();
return [{ json: out }];
